  "ME-F": {
   "name": "ME-F",
   "file": "globals.zil",
   "line": 444,
   "endLine": 490,
   "source": "<ROUTINE ME-F (\"AUX\" OLIT)\n\t <COND (<P? EXAMINE ,ME>\n\t\t<V-DIAGNOSE>)\n\t       (<VERB? TELL HELP>\n\t\t<MENTAL-COLLAPSE>\n\t\t<END-QUOTE>)\n\t       (<VERB? LISTEN>\n\t\t<TELL \"Yes?\" CR>)\n\t       (<VERB? WAKE>\n\t\t<TELL ,YOU-ARE>\n\t\t<TELL ,PERIOD>)\n\t       (<AND <WINNER? ,PLAYER>\n\t\t     <VERB? GIVE>>\n\t\t<COND (<PRSO? ,ME>\n\t\t       <TELL ,WASTE-OF-TIME>)\n\t\t      (<PRSI? ,ME>\n\t\t       <COND (<IN? ,PRSO ,PLAYER>\n\t\t\t      <PRE-TAKE>)\n\t\t\t     (T\n\t\t\t      <PERFORM ,V?TAKE ,PRSO>\n\t\t\t      <RTRUE>)>)>)\n\t       (<VERB? MOVE>\n\t\t<V-WALK-AROUND>)\n\t       (<VERB? SEARCH>\n\t\t<V-INVENTORY>\n\t\t<RTRUE>)\n\t       (<VERB? KILL MUNG BURY SMELL>\n\t\t<JIGS-UP\n\"Verdict: suicide while the balance of the mind was disturbed.\">\n\t\t<RTRUE>)\n\t       (<VERB? WHO>\n\t\t<V-WHAT>)\n\t       (<VERB? FOLLOW>\n\t\t<TELL\n\"You're getting ahead of yourself.\" CR>)\n\t       (<VERB? LOOK-BEHIND>\n\t\t<TELL\n\"You look back over your shoulder. \">\n\t\t<COND (<PROB 80>\n\t\t       <TELL\nS \"There's nothing \"\"there.\" CR>)\n\t\t      (<PROB 80>\n\t\t       <TELL\n\"Was that a flicker of movement in the distance?\" CR>)\n\t\t      (ELSE\n\t\t       <TELL\n\"You see something duck back into the shadows.\" CR>)>)>>"
  },
  "GLOBAL-ROOM-F": {
   "name": "GLOBAL-ROOM-F",
   "file": "globals.zil",
   "line": 499,
   "endLine": 516,
   "source": "<ROUTINE GLOBAL-ROOM-F ()\n\t <COND (<VERB? LOOK EXAMINE LOOK-INSIDE>\n\t\t<V-LOOK>\n\t\t<RTRUE>)\n\t       (<P? PUT * ,GLOBAL-ROOM>\n\t\t<PERFORM ,V?DROP ,PRSO>\n\t\t<RTRUE>)\n\t       (<VERB? THROUGH WALK-TO>\n\t\t<V-WALK-AROUND>)\n\t       (<VERB? DROP LEAVE EXIT>\n\t\t<DO-WALK ,P?OUT>)\n\t       (<VERB? WALK-AROUND>\n\t\t<TELL\n\"Walking around the room reveals nothing new. To move elsewhere, just type\nthe desired direction.\" CR>)\n\t       (<VERB? LAMP-ON>\n\t\t<NEW-PRSO ,LIGHT>\n\t\t<RTRUE>)>>"
  },
